#\n# @lc app=leetcode id=3729 lang=python3\n#\n# [3729] Count Distinct Subarrays Divisible by K in Sorted Array\n#\n\n# @lc code=start\nclass Solution:\n    def numGoodSubarrays(self, nums: List[int], k: int) -> int:\n        groups = []\n        i = 0\n        n = len(nums)\n        while i < n:\n            v = nums[i]\n            f = 0\n            while i < n and nums[i] == v:\n                f += 1\n                i += 1\n            groups.append((v, f))\n        m = len(groups)\n        pre_sum = [0] * (m + 1)\n        for j in range(m):\n            vj, fj = groups[j]\n            pre_sum[j + 1] = (pre_sum[j] + fj * (vj % k) % k) % k\n        ans = 0\n        # single-run subarrays\n        for v, f in groups:\n            cum = 0\n            vmod = v % k\n            for _ in range(f):\n                cum = (cum + vmod) % k\n                if cum == 0:\n                    ans += 1\n        # multi-run subarrays\n        freq = {}\n        for e in range(m):\n            v_e, f_e = groups[e]\n            ve_mod = v_e % k\n            target = pre_sum[e + 1]\n            contrib = 0\n            for _ in range(f_e):\n                needed = (target - contrib + k) % k\n                ans += freq.get(needed, 0)\n                contrib = (contrib + ve_mod) % k\n            # add left partials (prefix mods for suffixes)\n            base = pre_sum[e]\n            current = base % k\n            for _ in range(f_e):\n                freq[current] = freq.get(current, 0) + 1\n                current = (current + ve_mod) % k\n        return ans\n\n# @lc code=end